import { File } from 'node:buffer';

export const SAMPLE_PNG_BYTES = Buffer.from(
  'iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAIAAACQd1PeAAAADElEQVR4nGP4z8AAAAMBAQDJ/pLvAAAAAElFTkSuQmCC',
  'base64',
);

export const ALTERNATE_SAMPLE_PNG_BYTES = Buffer.from(
  'iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mP8/x8AAwMCAO3Z9FYAAAAASUVORK5CYII=',
  'base64',
);

export const SAMPLE_JPEG_BYTES = Buffer.from(
  '',
  'base64',
);

export function createPngAvatarFile(name = 'avatar.png', bytes: Uint8Array = SAMPLE_PNG_BYTES): File {
  return new File([bytes], name, { type: 'image/png' });
}

export function createJpegAvatarFile(name = 'avatar.jpg', bytes: Uint8Array = SAMPLE_JPEG_BYTES): File {
  return new File([bytes], name, { type: 'image/jpeg' });
}
